import re

with open('/tmp/isolated_workspace_1091/lab2.asm') as f:
    lines = f.readlines()

# Simulate assembly: assign addresses to all labels
# Starting from x3000
addr = 0x3000
label_addrs = {}
line_addrs = []  # (addr, line)

for lineno, line in enumerate(lines, 1):
    stripped = line.strip()
    if not stripped or stripped.startswith(';'):
        line_addrs.append(None)
        continue
    if stripped.upper().startswith('.ORIG'):
        parts = stripped.split()
        orig_val = parts[1]
        if orig_val.startswith('x') or orig_val.startswith('X'):
            addr = int(orig_val[1:], 16)
        else:
            addr = int(orig_val)
        line_addrs.append(None)
        continue
    if stripped.upper().startswith('.END'):
        line_addrs.append(None)
        continue

    code = stripped.split(';')[0].strip()
    if not code:
        line_addrs.append(None)
        continue

    tokens = code.split()

    # Detect label
    first = tokens[0]
    # Labels: start with letter, no colon needed in LC-3
    is_label = bool(re.match(r'^[A-Za-z][A-Za-z0-9_]*$', first))
    # Check if it's an opcode
    opcodes = {'ADD','AND','BR','BRN','BRZ','BRP','BRNZ','BRNP','BRZP','BRNZP',
               'JMP','JSR','JSRR','LD','LDI','LDR','LEA','NOT','RET','RTI',
               'ST','STI','STR','TRAP','GETC','OUT','PUTS','IN','PUTSP','HALT',
               'NOP','.FILL','.BLKW','.STRINGZ','.ORIG','.END'}

    if is_label and first.upper() not in opcodes:
        label_addrs[first] = addr
        # Rest of line is the instruction
        rest = tokens[1:] if len(tokens) > 1 else []
    else:
        rest = tokens

    if not rest:
        line_addrs.append((addr, lineno, line.rstrip()))
        addr += 1
        continue

    op = rest[0].upper()

    if op == '.FILL':
        line_addrs.append((addr, lineno, line.rstrip()))
        addr += 1
    elif op == '.BLKW':
        n = int(rest[1].lstrip('#')) if rest[1].startswith('#') else int(rest[1])
        line_addrs.append((addr, lineno, line.rstrip()))
        addr += n
    elif op == '.STRINGZ':
        # Count characters in string + null
        s = code[code.index(op)+len(op):].strip()
        if s.startswith('\"'):
            s = s[1:]
        if s.endswith('\"'):
            s = s[:-1]
        # Process escape sequences
        n = len(s.replace('\\n','X').replace('\\t','X')) + 1
        line_addrs.append((addr, lineno, line.rstrip()))
        addr += n
    else:
        # Regular instruction = 1 word
        line_addrs.append((addr, lineno, line.rstrip()))
        addr += 1

print(f'Total address range: x3000 to x{addr-1:04X} ({addr-0x3000} words)')
print()

# Now verify LD/ST/LEA offsets
errors = []
warnings = []
for entry in line_addrs:
    if entry is None:
        continue
    instr_addr, lineno, text = entry
    code = text.strip().split(';')[0].strip()
    tokens = code.split()
    # Remove label
    if tokens and re.match(r'^[A-Za-z][A-Za-z0-9_]*$', tokens[0]):
        opcodes_set = {'ADD','AND','BR','BRN','BRZ','BRP','BRNZ','BRNP','BRZP','BRNZP',
                   'JMP','JSR','JSRR','LD','LDI','LDR','LEA','NOT','RET','RTI',
                   'ST','STI','STR','TRAP','GETC','OUT','PUTS','IN','PUTSP','HALT',
                   'NOP','.FILL','.BLKW','.STRINGZ'}
        if tokens[0].upper() not in opcodes_set:
            tokens = tokens[1:]
    if not tokens:
        continue
    op = tokens[0].upper()
    if op in ('LD','ST','LEA','LDI','STI','BR','BRN','BRZ','BRP','BRNZ','BRNP','BRZP','BRNZP','JSR'):
        # Find label operand
        operands = ' '.join(tokens[1:]).replace(',', ' ').split()
        target_label = None
        if op in ('LD','ST','LEA','LDI','STI'):
            if len(operands) >= 2:
                target_label = operands[1]
        elif op == 'JSR':
            if operands:
                target_label = operands[0]
        elif op.startswith('BR'):
            if operands:
                target_label = operands[0]

        if target_label and target_label in label_addrs:
            target_addr = label_addrs[target_label]
            # PC-relative offset = target - (PC+1) = target - instr_addr - 1
            offset = target_addr - instr_addr - 1
            if op in ('LD','ST','LEA','LDI','STI'):
                if not (-256 <= offset <= 255):
                    errors.append(f'Line {lineno}: {op} {target_label} offset={offset} (EXCEEDS 9-bit range [-256,255]) at x{instr_addr:04X} -> x{target_addr:04X}')
            elif op == 'JSR':
                if not (-1024 <= offset <= 1023):
                    errors.append(f'Line {lineno}: JSR {target_label} offset={offset} (EXCEEDS 11-bit range) at x{instr_addr:04X} -> x{target_addr:04X}')
            elif op.startswith('BR'):
                if not (-256 <= offset <= 255):
                    errors.append(f'Line {lineno}: {op} {target_label} offset={offset} (EXCEEDS 9-bit range) at x{instr_addr:04X} -> x{target_addr:04X}')

if errors:
    print(f'ERRORS ({len(errors)}):')
    for e in errors:
        print(f'  {e}')
else:
    print('All PC-relative offsets are within range. ✓')
